// Aggregate data from all query nodes
const user = $('Get All Users').item.json;
const totals = $('Weekly Totals').all().map(i => i.json);
const categories = $('Top Categories').all().map(i => i.json);
const budgetAlerts = $('Budget Alerts').all().map(i => i.json);

const currency = user.currency || 'IDR';
const name = user.full_name || user.email.split('@')[0];

const fmt = (n) => {
  const num = Number(n);
  if (currency === 'IDR') return 'Rp ' + num.toLocaleString('id-ID');
  return currency + ' ' + num.toLocaleString();
};

const income = totals.find(r => r.transaction_type === 'income')?.total || 0;
const expense = totals.find(r => r.transaction_type === 'expense')?.total || 0;
const net = income - expense;
const txCount = totals.reduce((s, r) => s + Number(r.count), 0);

// Build category rows
const catRows = categories.map(c =>
  `<tr><td style="padding:6px 12px;border-bottom:1px solid #e5eeff">${c.category}</td>
   <td style="padding:6px 12px;border-bottom:1px solid #e5eeff;text-align:right;font-weight:600">${fmt(c.total)}</td>
   <td style="padding:6px 12px;border-bottom:1px solid #e5eeff;color:#757684">${c.count} tx</td></tr>`
).join('');

// Build budget alert rows
const budgetRows = budgetAlerts.map(b => {
  const over = Number(b.pct) >= 100;
  return `<tr><td style="padding:6px 12px">${b.category}</td>
    <td style="padding:6px 12px;text-align:right">${fmt(b.spent)} / ${fmt(b.budget)}</td>
    <td style="padding:6px 12px;font-weight:700;color:${over ? '#ba1a1a' : '#d97706'}">${b.pct}% ${over ? '🚨' : '⚠️'}</td></tr>`;
}).join('');

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);
const dateRange = weekStart.toLocaleDateString('id-ID', {day:'2-digit',month:'short'}) + ' – ' +
  new Date().toLocaleDateString('id-ID', {day:'2-digit',month:'short',year:'numeric'});

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"></head>
<body style="font-family:Inter,system-ui,sans-serif;background:#f8f9ff;margin:0;padding:20px">
<div style="max-width:560px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(30,64,175,0.08)">

  <!-- Header -->
  <div style="background:#00288e;padding:32px;color:#fff">
    <div style="font-size:24px;font-weight:700;margin-bottom:4px">FinTrack AI</div>
    <div style="opacity:0.8;font-size:14px">Weekly Report · ${dateRange}</div>
    <div style="margin-top:12px;font-size:16px">Halo, <strong>${name}</strong>! 👋</div>
  </div>

  <!-- Summary Cards -->
  <div style="display:flex;gap:0;border-bottom:1px solid #e5eeff">
    <div style="flex:1;padding:20px;text-align:center;border-right:1px solid #e5eeff">
      <div style="font-size:12px;color:#757684;text-transform:uppercase;letter-spacing:.05em">Pemasukan</div>
      <div style="font-size:20px;font-weight:700;color:#006c49;margin-top:4px">${fmt(income)}</div>
    </div>
    <div style="flex:1;padding:20px;text-align:center;border-right:1px solid #e5eeff">
      <div style="font-size:12px;color:#757684;text-transform:uppercase;letter-spacing:.05em">Pengeluaran</div>
      <div style="font-size:20px;font-weight:700;color:#00288e;margin-top:4px">${fmt(expense)}</div>
    </div>
    <div style="flex:1;padding:20px;text-align:center">
      <div style="font-size:12px;color:#757684;text-transform:uppercase;letter-spacing:.05em">Neto</div>
      <div style="font-size:20px;font-weight:700;color:${net >= 0 ? '#006c49' : '#ba1a1a'};margin-top:4px">${net >= 0 ? '+' : ''}${fmt(net)}</div>
    </div>
  </div>

  <div style="padding:24px">
    <div style="color:#757684;font-size:13px;margin-bottom:16px">${txCount} transaksi minggu ini</div>

    ${categories.length > 0 ? `
    <!-- Top Categories -->
    <h3 style="font-size:15px;font-weight:600;color:#0b1c30;margin:0 0 12px">Kategori Teratas</h3>
    <table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:24px">
      <thead><tr style="background:#eff4ff">
        <th style="padding:8px 12px;text-align:left;font-weight:600;color:#444653">Kategori</th>
        <th style="padding:8px 12px;text-align:right;font-weight:600;color:#444653">Total</th>
        <th style="padding:8px 12px;font-weight:600;color:#444653">Tx</th>
      </tr></thead>
      <tbody>${catRows}</tbody>
    </table>` : ''}

    ${budgetAlerts.length > 0 ? `
    <!-- Budget Alerts -->
    <h3 style="font-size:15px;font-weight:600;color:#ba1a1a;margin:0 0 12px">⚠️ Budget Alert</h3>
    <table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:24px;border:1px solid #ffdad6;border-radius:8px;overflow:hidden">
      <thead><tr style="background:#ffdad6">
        <th style="padding:8px 12px;text-align:left">Kategori</th>
        <th style="padding:8px 12px;text-align:right">Terpakai / Budget</th>
        <th style="padding:8px 12px">%</th>
      </tr></thead>
      <tbody>${budgetRows}</tbody>
    </table>` : '<p style="color:#006c49;font-size:14px">✅ Semua budget dalam batas aman minggu ini.</p>'}

    <!-- CTA -->
    <div style="text-align:center;margin-top:24px">
      <a href="${process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000'}/dashboard"
         style="display:inline-block;background:#00288e;color:#fff;padding:12px 32px;border-radius:8px;text-decoration:none;font-weight:600;font-size:14px">
        Buka Dashboard →
      </a>
    </div>
  </div>

  <!-- Footer -->
  <div style="background:#f8f9ff;padding:16px 24px;text-align:center;color:#757684;font-size:12px;border-top:1px solid #e5eeff">
    FinTrack AI · Laporan otomatis tiap Senin pukul 08:00
  </div>
</div>
</body></html>`;

return [{ json: { user_id: user.user_id, email: user.email, name, html, subject: `📊 Laporan Mingguan FinTrack — ${dateRange}` } }];
